Python 的数据结构 List Tuple Dict Set两个辅助函数让你学习更轻松 help (查看方法的使用方式) dir(查看类的子方法)12a = "life is short use Python"print(dir(a))[&apos;__add__&apos;, &apos;__class__&apos;, &apos;__contains__&apos;, &apos;__delattr__&apos;, &apos;__dir__&apos;, &apos;__doc__&apos;, &apos;__eq__&apos;, &apos;__format__&apos;, &apos;__ge__&apos;, &apos;__getattribute__&apos;, &apos;__getitem__&apos;, &apos;__getnewargs__&apos;, &apos;__gt__&apos;, &apos;__hash__&apos;, &apos;__init__&apos;, &apos;__init_subclass__&apos;, &apos;__iter__&apos;, &apos;__le__&apos;, &apos;__len__&apos;, &apos;__lt__&apos;, &apos;__mod__&apos;, &apos;__mul__&apos;, &apos;__ne__&apos;, &apos;__new__&apos;, &apos;__reduce__&apos;, &apos;__reduce_ex__&apos;, &apos;__repr__&apos;, &apos;__rmod__&apos;, &apos;__rmul__&apos;, &apos;__setattr__&apos;, &apos;__sizeof__&apos;, &apos;__str__&apos;, &apos;__subclasshook__&apos;, &apos;capitalize&apos;, &apos;casefold&apos;, &apos;center&apos;, &apos;count&apos;, &apos;encode&apos;, &apos;endswith&apos;, &apos;expandtabs&apos;, &apos;find&apos;, &apos;format&apos;, &apos;format_map&apos;, &apos;index&apos;, &apos;isalnum&apos;, &apos;isalpha&apos;, &apos;isascii&apos;, &apos;isdecimal&apos;, &apos;isdigit&apos;, &apos;isidentifier&apos;, &apos;islower&apos;, &apos;isnumeric&apos;, &apos;isprintable&apos;, &apos;isspace&apos;, &apos;istitle&apos;, &apos;isupper&apos;, &apos;join&apos;, &apos;ljust&apos;, &apos;lower&apos;, &apos;lstrip&apos;, &apos;maketrans&apos;, &apos;partition&apos;, &apos;replace&apos;, &apos;rfind&apos;, &apos;rindex&apos;, &apos;rjust&apos;, &apos;rpartition&apos;, &apos;rsplit&apos;, &apos;rstrip&apos;, &apos;split&apos;, &apos;splitlines&apos;, &apos;startswith&apos;, &apos;strip&apos;, &apos;swapcase&apos;, &apos;title&apos;, &apos;translate&apos;, &apos;upper&apos;, &apos;zfill&apos;] 1help(a.strip) Help on built-in function strip: strip(chars=None, /) method of builtins.str instance Return a copy of the string with leading and trailing whitespace remove. If chars is given and not None, remove characters in chars instead.列表list 是一种有序的集合，可以随时添加和删除其中的元素list 是一个可变的有序表 12heros = ['iron man', 'spider man', 'egg man']print(f'&#123;heros&#125; 
 type: &#123;type(heros)&#125;') [&apos;iron man&apos;, &apos;spider man&apos;, &apos;egg man&apos;] type: &lt;class &apos;list&apos;&gt;1len(heros) # 获取列表的长度 31heros[0] # 角标从0开始 默认是长度-1 &apos;iron man&apos;1heros[1] &apos;spider man&apos;1heros[3] # 超出索引 --------------------------------------------------------------------------- IndexError Traceback (most recent call last) &lt;ipython-input-75-8dc1ea78ff1c&gt; in &lt;module&gt; ----&gt; 1 heros[3] # 超出索引 IndexError: list index out of range1heros[-1] # 从后往前取值 &apos;egg man&apos;1heros.insert(3, 'wo man') # 指定索引插入 1heros [&apos;iron man&apos;, &apos;spider man&apos;, &apos;egg man&apos;, &apos;wo man&apos;]1heros[3] = 'woo man' # 更新元素 1heros [&apos;iron man&apos;, &apos;spider man&apos;, &apos;egg man&apos;, &apos;woo man&apos;]1heros.pop() # 弹出最后一个元素并返回 &apos;woo man&apos;1heros [&apos;iron man&apos;, &apos;spider man&apos;, &apos;egg man&apos;]1heros.pop(1) # 指定索弹出元素 &apos;spider man&apos;1heros [&apos;iron man&apos;, &apos;egg man&apos;]1heros.append('add man') # 追加元素到列表 1heros [&apos;iron man&apos;, &apos;egg man&apos;, &apos;add man&apos;]元组tuple 和 list 非常类似，但是 tuple 一旦初始化就不能修改 12t = ()print(f"&#123;t&#125; 
 &#123;type(t)&#125;") () &lt;class &apos;tuple&apos;&gt;12t = (2) # (2)一个元素时 不能这样定义print(f"&#123;t&#125; 
 &#123;type(t)&#125;") 2 &lt;class &apos;int&apos;&gt;12tt = (2,) # 只有1个元素的tuple时，也会加一个逗号,print(f"&#123;tt&#125; 
 &#123;type(tt)&#125;") (2,) &lt;class &apos;tuple&apos;&gt;1print(dir(tt)) # 元组的属性 [&apos;__add__&apos;, &apos;__class__&apos;, &apos;__contains__&apos;, &apos;__delattr__&apos;, &apos;__dir__&apos;, &apos;__doc__&apos;, &apos;__eq__&apos;, &apos;__format__&apos;, &apos;__ge__&apos;, &apos;__getattribute__&apos;, &apos;__getitem__&apos;, &apos;__getnewargs__&apos;, &apos;__gt__&apos;, &apos;__hash__&apos;, &apos;__init__&apos;, &apos;__init_subclass__&apos;, &apos;__iter__&apos;, &apos;__le__&apos;, &apos;__len__&apos;, &apos;__lt__&apos;, &apos;__mul__&apos;, &apos;__ne__&apos;, &apos;__new__&apos;, &apos;__reduce__&apos;, &apos;__reduce_ex__&apos;, &apos;__repr__&apos;, &apos;__rmul__&apos;, &apos;__setattr__&apos;, &apos;__sizeof__&apos;, &apos;__str__&apos;, &apos;__subclasshook__&apos;, &apos;count&apos;, &apos;index&apos;]1demo = (1,2,[2, 8]) 1demo[2][0] = 100 1demo # 此时tuple内元素变了 那可以说 tuple为可变序列吗? (1, 2, [100, 8])字典12kw = &#123;"name": "test", "age": 12&#125;print(f"&#123;kw&#125; 
 &#123;type(kw)&#125;") {&apos;name&apos;: &apos;test&apos;, &apos;age&apos;: 12} &lt;class &apos;dict&apos;&gt;1kw['name'] &apos;test&apos;1kw['name1'] # key找不到空报错 --------------------------------------------------------------------------- KeyError Traceback (most recent call last) &lt;ipython-input-96-69178caa756c&gt; in &lt;module&gt; ----&gt; 1 kw[&apos;name1&apos;] # key找不到空报错 KeyError: &apos;name1&apos;1kw.get('name1', None) # key找不到, 返回None 12kw['sex'] = 'man' # 增加字段kw {&apos;name&apos;: &apos;test&apos;, &apos;age&apos;: 12, &apos;sex&apos;: &apos;man&apos;}12kw.pop('age') # 删除字段kw {&apos;name&apos;: &apos;test&apos;, &apos;sex&apos;: &apos;man&apos;}1print(dir(kw)) [&apos;__class__&apos;, &apos;__contains__&apos;, &apos;__delattr__&apos;, &apos;__delitem__&apos;, &apos;__dir__&apos;, &apos;__doc__&apos;, &apos;__eq__&apos;, &apos;__format__&apos;, &apos;__ge__&apos;, &apos;__getattribute__&apos;, &apos;__getitem__&apos;, &apos;__gt__&apos;, &apos;__hash__&apos;, &apos;__init__&apos;, &apos;__init_subclass__&apos;, &apos;__iter__&apos;, &apos;__le__&apos;, &apos;__len__&apos;, &apos;__lt__&apos;, &apos;__ne__&apos;, &apos;__new__&apos;, &apos;__reduce__&apos;, &apos;__reduce_ex__&apos;, &apos;__repr__&apos;, &apos;__setattr__&apos;, &apos;__setitem__&apos;, &apos;__sizeof__&apos;, &apos;__str__&apos;, &apos;__subclasshook__&apos;, &apos;clear&apos;, &apos;copy&apos;, &apos;fromkeys&apos;, &apos;get&apos;, &apos;items&apos;, &apos;keys&apos;, &apos;pop&apos;, &apos;popitem&apos;, &apos;setdefault&apos;, &apos;update&apos;, &apos;values&apos;]set 和 dict 类似，也是一组 key 的集合，但不存储 value。由于 key 不能重复，所以，在 set 中，没有重复的 key 12s = set([1,2,3,4])s {1, 2, 3, 4}12s.add(4) # 增加 元素中有的 不添加s {1, 2, 3, 4}12s.add(33)s {1, 2, 3, 4, 33}12s.remove(2) # 删除keys {1, 3, 4, 33}12ss = set([3,4]) # 数学交集s&amp;ss {3, 4}
